import math

def is_prime(n):
    if n <= 1:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    i = 3
    while i * i <= n:
        if n % i == 0:
            return False
        i += 2
    return True

def primes_generator():
    num = 2
    while True:
        if is_prime(num):
            yield num
        num += 1

if __name__ == "__main__":
    prime_gen = primes_generator()
    print("İlk 10 asal sayı:")
    for _ in range(10):
        print(next(prime_gen))

    print("\nSonraki 5 asal sayı:")
    for _ in range(5):
        print(next(prime_gen))
